    assert_eq!(txt, "8E 52 20 47 78 78 51 B7 BB 55 6A 78 71 84 72 58 ");

    let mut recovered = String::new();
    a_des.decrypt_array_with_padding_iso_into_string(&cipher, &mut recovered);
