    let mut cipher2 = [0_u8; 55];
    c_des.encrypt_cfb(iv, message.as_ptr(), message.len() as u64, cipher1.as_mut_ptr());
    d_des.encrypt_cfb(iv, message.as_ptr(), message.len() as u64, cipher2.as_mut_ptr());
    print!("C (0 rounds) =\t");
